/**
 * APP 平台适配器
 * 实现原生 APP 环境的操作
 */

import type { PlatformAdapter, PlatformType } from '../core/interfaces';

export class AppAdapter implements PlatformAdapter {
  /**
   * 平台类型
   */
  platform: PlatformType = 'app';

  /**
   * 创建DOM元素
   * @param tag 标签名
   * @param options 选项
   */
  createElement(tag: string, options: Record<string, any> = {}): any {
    // APP环境下，元素创建由原生代码处理
    // 这里返回一个模拟对象
    return {
      tag,
      className: options.className || '',
      id: options.id || '',
      style: options.style || {},
      attributes: options.attributes || {},
      nativeElement: null,
    };
  }

  /**
   * 获取元素
   * @param selector 选择器
   */
  querySelector(selector: string): any {
    // APP环境下，使用原生方法获取元素
    console.log('Query selector:', selector);
    return null;
  }

  /**
   * 获取多个元素
   * @param selector 选择器
   */
  querySelectorAll(selector: string): any[] {
    // APP环境下，使用原生方法获取多个元素
    console.log('Query selector all:', selector);
    return [];
  }

  /**
   * 添加事件监听
   * @param element 元素
   * @param event 事件名
   * @param handler 事件处理函数
   */
  addEventListener(element: any, event: string, handler: Function): void {
    // APP环境下，事件绑定通过原生桥接
    console.log('Add event listener:', event);
  }

  /**
   * 移除事件监听
   * @param element 元素
   * @param event 事件名
   * @param handler 事件处理函数
   */
  removeEventListener(element: any, event: string, handler: Function): void {
    // APP环境下，事件解绑通过原生桥接
    console.log('Remove event listener:', event);
  }

  /**
   * 设置元素属性
   * @param element 元素
   * @param key 属性名
   * @param value 属性值
   */
  setAttribute(element: any, key: string, value: any): void {
    if (element) {
      element[key] = value;
    }
  }

  /**
   * 获取元素属性
   * @param element 元素
   * @param key 属性名
   */
  getAttribute(element: any, key: string): string | null {
    return element?.[key] || null;
  }

  /**
   * 添加样式类
   * @param element 元素
   * @param className 类名
   */
  addClass(element: any, className: string): void {
    if (element) {
      element.className = element.className || '';
      const classList = element.className.split(' ').filter(c => c);
      if (!classList.includes(className)) {
        element.className = [...classList, className].join(' ');
      }
    }
  }

  /**
   * 移除样式类
   * @param element 元素
   * @param className 类名
   */
  removeClass(element: any, className: string): void {
    if (element && element.className) {
      const classList = element.className.split(' ');
      element.className = classList.filter(c => c !== className).join(' ');
    }
  }

  /**
   * 切换样式类
   * @param element 元素
   * @param className 类名
   * @param force 是否强制添加/移除
   */
  toggleClass(element: any, className: string, force?: boolean): boolean {
    if (!element || !element.className) return false;
    
    const classList = element.className.split(' ');
    const hasClass = classList.includes(className);
    
    if (force !== undefined) {
      if (force && !hasClass) {
        element.className = [...classList, className].join(' ');
        return true;
      } else if (!force && hasClass) {
        element.className = classList.filter(c => c !== className).join(' ');
        return false;
      }
      return hasClass;
    }
    
    if (hasClass) {
      element.className = classList.filter(c => c !== className).join(' ');
      return false;
    } else {
      element.className = [...classList, className].join(' ');
      return true;
    }
  }

  /**
   * 设置样式
   * @param element 元素
   * @param style 样式对象
   */
  setStyle(element: any, style: Record<string, any>): void {
    if (element) {
      element.style = { ...element.style, ...style };
    }
  }

  /**
   * 创建文本节点
   * @param text 文本内容
   */
  createTextNode(text: string): any {
    return {
      type: 'text',
      text,
    };
  }

  /**
   * 添加子元素
   * @param parent 父元素
   * @param child 子元素
   */
  appendChild(parent: any, child: any): void {
    console.log('Append child:', child);
  }

  /**
   * 移除子元素
   * @param parent 父元素
   * @param child 子元素
   */
  removeChild(parent: any, child: any): void {
    console.log('Remove child:', child);
  }

  /**
   * 获取父元素
   * @param element 元素
   */
  getParent(element: any): any {
    return element?.parent || null;
  }

  /**
   * 获取子元素
   * @param element 元素
   */
  getChildren(element: any): any[] {
    return element?.children || [];
  }

  /**
   * 显示元素
   * @param element 元素
   */
  show(element: any): void {
    console.log('Show element');
  }

  /**
   * 隐藏元素
   * @param element 元素
   */
  hide(element: any): void {
    console.log('Hide element');
  }

  /**
   * 获取元素尺寸
   * @param element 元素
   */
  getBoundingClientRect(element: any): {
    width: number;
    height: number;
    top: number;
    left: number;
    bottom: number;
    right: number;
  } {
    return {
      width: 0,
      height: 0,
      top: 0,
      left: 0,
      bottom: 0,
      right: 0,
    };
  }

  /**
   * 获取窗口尺寸
   */
  getWindowSize(): { width: number; height: number } {
    // APP环境下，通过原生方法获取窗口尺寸
    return {
      width: window.innerWidth || 375,
      height: window.innerHeight || 667,
    };
  }

  /**
   * 动画
   * @param element 元素
   * @param props 属性
   * @param duration 持续时间
   * @param callback 回调函数
   */
  animate(element: any, props: Record<string, any>, duration: number, callback?: Function): void {
    // APP环境下，动画通过原生桥接实现
    console.log('Animate element:', props);
    
    setTimeout(() => {
      callback?.();
    }, duration);
  }

  /**
   * 定时器
   * @param callback 回调函数
   * @param delay 延迟时间
   */
  setTimeout(callback: Function, delay: number): number {
    return setTimeout(callback, delay);
  }

  /**
   * 清除定时器
   * @param timerId 定时器ID
   */
  clearTimeout(timerId: number): void {
    clearTimeout(timerId);
  }

  /**
   * 防抖函数
   * @param fn 函数
   * @param delay 延迟时间
   */
  debounce<T extends (...args: any[]) => any>(fn: T, delay: number): (...args: Parameters<T>) => void {
    let timer: number | null = null;
    
    return function(...args: Parameters<T>) {
      if (timer) {
        clearTimeout(timer);
      }
      
      timer = setTimeout(() => {
        fn.apply(this, args);
      }, delay);
    };
  }

  /**
   * 节流函数
   * @param fn 函数
   * @param interval 间隔时间
   */
  throttle<T extends (...args: any[]) => any>(fn: T, interval: number): (...args: Parameters<T>) => void {
    let lastTime = 0;
    
    return function(...args: Parameters<T>) {
      const now = Date.now();
      
      if (now - lastTime >= interval) {
        lastTime = now;
        fn.apply(this, args);
      }
    };
  }
}