/**
 * Tbe UI - 现代化的多平台UI组件库
 * 版本: 2.0.0
 * 描述: 支持Web、微信小程序、APP的跨平台UI组件库
 */

import { PlatformManager } from '../platforms/PlatformManager';
import { Radio, Checkbox } from '../components';
import { PluginManager, type Plugin } from '../core/PluginManager';
import '../tbeui.css';

// 初始化平台管理器
PlatformManager.init();

/**
 * TbeUI 主类
 */
class TbeUI {
  /**
   * 平台管理器
   */
  static Platform = PlatformManager;

  /**
   * 插件管理器
   */
  static Plugin = new PluginManager(this);

  /**
   * 组件
   */
  static Components = {
    Radio,
    Checkbox
    // 后续会添加更多组件
  };

  /**
   * Radio 组件
   */
  static Radio = Radio;

  /**
   * Checkbox 组件
   */
  static Checkbox = Checkbox;

  /**
   * 初始化所有组件
   */
  static init(): void {
    // 初始化Radio组件
    const radio = new Radio('radio');
    radio.init();

    // 初始化Checkbox组件
    const checkbox = new Checkbox('checkbox');
    checkbox.init();
  }

  /**
   * 获取当前平台类型
   */
  static getPlatform(): string {
    return PlatformManager.getPlatform();
  }

  /**
   * 手动设置平台
   * @param platform 平台类型
   */
  static setPlatform(platform: 'web' | 'wechat' | 'app'): void {
    PlatformManager.setPlatform(platform);
  }

  /**
   * 注册插件
   * @param plugin 插件对象
   */
  static use(plugin: Plugin): typeof TbeUI {
    this.Plugin.register(plugin);
    return this;
  }

  /**
   * 启用插件
   * @param pluginName 插件名称
   */
  static enablePlugin(pluginName: string): boolean {
    return this.Plugin.enable(pluginName);
  }

  /**
   * 禁用插件
   * @param pluginName 插件名称
   */
  static disablePlugin(pluginName: string): boolean {
    return this.Plugin.disable(pluginName);
  }

  /**
   * 获取插件
   * @param pluginName 插件名称
   */
  static getPlugin(pluginName: string): Plugin | undefined {
    return this.Plugin.getPlugin(pluginName);
  }

  /**
   * 获取所有插件
   */
  static getAllPlugins(): Plugin[] {
    return this.Plugin.getAllPlugins();
  }
}

// 导出TbeUI
export default TbeUI;

// 全局导出（兼容旧版）
if (typeof window !== 'undefined') {
  (window as any).TbeUI = TbeUI;
}

// CommonJS导出（兼容旧版）
if (typeof module !== 'undefined' && module.exports) {
  module.exports = TbeUI;
}