/**
 * 平台管理器
 * 负责管理和选择合适的平台适配器
 */

import type { PlatformAdapter, PlatformType } from '../core/interfaces';
import { WebAdapter } from '../adapters/webAdapter';
import { WechatAdapter } from '../adapters/wechatAdapter';
import { AppAdapter } from '../adapters/appAdapter';

export class PlatformManager {
  /**
   * 当前平台类型
   */
  private static platform: PlatformType = 'unknown';

  /**
   * 当前平台适配器实例
   */
  private static adapter: PlatformAdapter | null = null;

  /**
   * 初始化平台管理器
   * 自动检测当前运行环境并选择合适的适配器
   */
  static init(): void {
    this.detectPlatform();
    this.createAdapter();
  }

  /**
   * 检测当前平台
   */
  private static detectPlatform(): void {
    if (typeof wx !== 'undefined' && typeof wx.getSystemInfoSync === 'function') {
      // 微信小程序环境
      this.platform = 'wechat';
    } else if (typeof window !== 'undefined' && typeof document !== 'undefined') {
      // Web浏览器环境
      this.platform = 'web';
    } else {
      // APP环境或其他环境
      this.platform = 'app';
    }
  }

  /**
   * 创建平台适配器
   */
  private static createAdapter(): void {
    switch (this.platform) {
      case 'web':
        this.adapter = new WebAdapter();
        break;
      case 'wechat':
        this.adapter = new WechatAdapter();
        break;
      case 'app':
        this.adapter = new AppAdapter();
        break;
      default:
        this.adapter = new WebAdapter(); // 默认使用Web适配器
    }
  }

  /**
   * 获取当前平台类型
   */
  static getPlatform(): PlatformType {
    return this.platform;
  }

  /**
   * 获取平台适配器
   */
  static getAdapter(): PlatformAdapter {
    if (!this.adapter) {
      this.init();
    }
    return this.adapter!;
  }

  /**
   * 手动设置平台
   * @param platform 平台类型
   */
  static setPlatform(platform: PlatformType): void {
    this.platform = platform;
    this.createAdapter();
  }

  /**
   * 检查是否为Web平台
   */
  static isWeb(): boolean {
    return this.platform === 'web';
  }

  /**
   * 检查是否为微信小程序平台
   */
  static isWechat(): boolean {
    return this.platform === 'wechat';
  }

  /**
   * 检查是否为APP平台
   */
  static isApp(): boolean {
    return this.platform === 'app';
  }
}