/**
 * Radio 单选框组件
 * 支持多平台的单选框组件
 */

import { BaseComponent } from './BaseComponent';

export class Radio extends BaseComponent {
  /**
   * 构造函数
   * @param id 组件ID
   * @param props 组件属性
   */
  constructor(id: string, props: Record<string, any> = {}) {
    super(id, 'radio', props);
  }

  /**
   * 组件挂载后钩子
   */
  protected mounted(): void {
    this.initRadioElements();
    this.initRadioButtons();
  }

  /**
   * 初始化 Radio 元素
   */
  private initRadioElements(): void {
    const radioInputs = this.getElements('.t-radio__input');
    
    radioInputs.forEach(radio => {
      this.updateCheckedState(radio);
      
      this.addEventListener(radio, 'change', () => {
        if (radio.name) {
          this.getElements(`input[name="${radio.name}"]`).forEach(r => {
            this.updateCheckedState(r);
          });
        } else {
          this.updateCheckedState(radio);
        }
      });
    });
  }

  /**
   * 初始化 Radio Button 元素
   */
  private initRadioButtons(): void {
    const radioButtons = this.getElements('.t-radio-button');
    
    radioButtons.forEach(button => {
      this.addEventListener(button, 'click', () => {
        const groupName = button.parentElement?.dataset?.group || 'default';
        this.selectButton(button, groupName);
      });
    });
  }

  /**
   * 更新 Radio 选中状态
   * @param radio radio输入元素
   */
  updateCheckedState(radio: any): void {
    const parent = this.getParent(radio);
    if (parent && parent.classList && parent.classList.contains && parent.classList.contains('t-radio')) {
      const isChecked = radio.checked;
      this.toggleClass(parent, 'is-checked', isChecked);
      this.setAttribute(parent, 'aria-checked', isChecked.toString());
      
      // 更新同组其他radio
      if (isChecked && radio.name) {
        this.getElements(`input[name="${radio.name}"]`).forEach(r => {
          if (r !== radio) {
            const p = this.getParent(r);
            if (p && p.classList && p.classList.contains && p.classList.contains('t-radio')) {
              this.removeClass(p, 'is-checked');
              this.setAttribute(p, 'aria-checked', 'false');
            }
          }
        });
      }
      
      // 使用事件系统触发状态变化事件
      this.emit('t:radio:change', {
        value: radio.value,
        group: radio.name || 'default',
        checked: isChecked
      });
    }
  }

  /**
   * 选择 Radio Button 样式
   * @param button 按钮元素
   * @param groupName 组名
   */
  selectButton(button: any, groupName: string): void {
    const group = this.getParent(button);
    if (group) {
      const buttons = this.getChildren(group);
      
      buttons.forEach(btn => {
        if (btn.classList && btn.classList.contains && btn.classList.contains('t-radio-button')) {
          this.removeClass(btn, 'is-active');
          this.setAttribute(btn, 'aria-checked', 'false');
        }
      });
      
      this.addClass(button, 'is-active');
      this.setAttribute(button, 'aria-checked', 'true');
      
      // 使用事件系统触发状态变化事件
      this.emit('t:radio:change', {
        value: button.dataset?.value || button.textContent,
        group: groupName,
        checked: true
      });
    }
  }

  /**
   * 选择 Radio Button 样式（兼容旧版调用方式）
   * @param button 按钮元素
   * @param groupName 组名
   */
  selectRadioButton(button: any, groupName: string): void {
    this.selectButton(button, groupName);
  }
}