/**
 * 插件管理器类
 * 支持插件注册、启用、禁用和生命周期管理
 */

export interface Plugin {
  /**
   * 插件名称
   */
  name: string;
  
  /**
   * 插件版本
   */
  version?: string;
  
  /**
   * 插件描述
   */
  description?: string;
  
  /**
   * 插件初始化方法
   * @param context 上下文对象
   */
  install?: (context: any) => void;
  
  /**
   * 插件启用方法
   */
  enable?: () => void;
  
  /**
   * 插件禁用方法
   */
  disable?: () => void;
  
  /**
   * 插件销毁方法
   */
  destroy?: () => void;
  
  /**
   * 插件选项
   */
  options?: Record<string, any>;
}

export class PluginManager {
  /**
   * 已注册的插件映射表
   */
  private plugins: Map<string, Plugin> = new Map();
  
  /**
   * 已启用的插件集合
   */
  private enabledPlugins: Set<string> = new Set();
  
  /**
   * 插件上下文
   */
  private context: any;
  
  /**
   * 构造函数
   * @param context 插件上下文
   */
  constructor(context: any) {
    this.context = context;
  }
  
  /**
   * 注册插件
   * @param plugin 插件对象
   */
  register(plugin: Plugin): this {
    if (!plugin.name) {
      throw new Error('Plugin must have a name');
    }
    
    if (this.plugins.has(plugin.name)) {
      console.warn(`Plugin "${plugin.name}" is already registered`);
      return this;
    }
    
    this.plugins.set(plugin.name, plugin);
    
    // 如果插件有install方法，自动执行
    if (typeof plugin.install === 'function') {
      plugin.install(this.context);
    }
    
    return this;
  }
  
  /**
   * 启用插件
   * @param pluginName 插件名称
   */
  enable(pluginName: string): boolean {
    const plugin = this.plugins.get(pluginName);
    
    if (!plugin) {
      console.error(`Plugin "${pluginName}" is not registered`);
      return false;
    }
    
    if (this.enabledPlugins.has(pluginName)) {
      console.warn(`Plugin "${pluginName}" is already enabled`);
      return true;
    }
    
    // 执行插件启用方法
    if (typeof plugin.enable === 'function') {
      plugin.enable();
    }
    
    this.enabledPlugins.add(pluginName);
    return true;
  }
  
  /**
   * 禁用插件
   * @param pluginName 插件名称
   */
  disable(pluginName: string): boolean {
    const plugin = this.plugins.get(pluginName);
    
    if (!plugin) {
      console.error(`Plugin "${pluginName}" is not registered`);
      return false;
    }
    
    if (!this.enabledPlugins.has(pluginName)) {
      console.warn(`Plugin "${pluginName}" is not enabled`);
      return true;
    }
    
    // 执行插件禁用方法
    if (typeof plugin.disable === 'function') {
      plugin.disable();
    }
    
    this.enabledPlugins.delete(pluginName);
    return true;
  }
  
  /**
   * 获取插件
   * @param pluginName 插件名称
   */
  getPlugin(pluginName: string): Plugin | undefined {
    return this.plugins.get(pluginName);
  }
  
  /**
   * 获取所有注册的插件
   */
  getAllPlugins(): Plugin[] {
    return Array.from(this.plugins.values());
  }
  
  /**
   * 获取已启用的插件
   */
  getEnabledPlugins(): Plugin[] {
    return Array.from(this.enabledPlugins).map(name => this.plugins.get(name)!).filter(Boolean);
  }
  
  /**
   * 检查插件是否已注册
   * @param pluginName 插件名称
   */
  hasPlugin(pluginName: string): boolean {
    return this.plugins.has(pluginName);
  }
  
  /**
   * 检查插件是否已启用
   * @param pluginName 插件名称
   */
  isEnabled(pluginName: string): boolean {
    return this.enabledPlugins.has(pluginName);
  }
  
  /**
   * 销毁所有插件
   */
  destroy(): void {
    // 先禁用所有插件
    this.enabledPlugins.forEach(pluginName => {
      this.disable(pluginName);
    });
    
    // 执行所有插件的销毁方法
    this.plugins.forEach(plugin => {
      if (typeof plugin.destroy === 'function') {
        plugin.destroy();
      }
    });
    
    // 清空插件集合
    this.plugins.clear();
    this.enabledPlugins.clear();
  }
}
