/**
 * 事件发射器类
 * 支持订阅/发布模式的事件系统
 */

export class EventEmitter {
  /**
   * 事件监听器映射表
   */
  private listeners: Map<string, Set<Function>> = new Map();

  /**
   * 订阅事件
   * @param eventName 事件名称
   * @param handler 事件处理函数
   */
  on(eventName: string, handler: Function): this {
    if (!this.listeners.has(eventName)) {
      this.listeners.set(eventName, new Set());
    }
    this.listeners.get(eventName)!.add(handler);
    return this;
  }

  /**
   * 订阅事件（仅触发一次）
   * @param eventName 事件名称
   * @param handler 事件处理函数
   */
  once(eventName: string, handler: Function): this {
    const onceHandler = (...args: any[]) => {
      handler(...args);
      this.off(eventName, onceHandler);
    };
    return this.on(eventName, onceHandler);
  }

  /**
   * 取消订阅事件
   * @param eventName 事件名称
   * @param handler 事件处理函数（可选，不传则取消所有该事件的订阅）
   */
  off(eventName: string, handler?: Function): this {
    if (!this.listeners.has(eventName)) {
      return this;
    }

    if (handler) {
      this.listeners.get(eventName)!.delete(handler);
      // 如果该事件没有监听器了，删除该事件
      if (this.listeners.get(eventName)!.size === 0) {
        this.listeners.delete(eventName);
      }
    } else {
      // 取消所有该事件的订阅
      this.listeners.delete(eventName);
    }

    return this;
  }

  /**
   * 发布事件
   * @param eventName 事件名称
   * @param args 事件参数
   */
  emit(eventName: string, ...args: any[]): boolean {
    if (!this.listeners.has(eventName)) {
      return false;
    }

    const handlers = this.listeners.get(eventName)!;
    handlers.forEach(handler => {
      try {
        handler(...args);
      } catch (error) {
        console.error(`Error in event handler for ${eventName}:`, error);
      }
    });

    return true;
  }

  /**
   * 获取事件的监听器数量
   * @param eventName 事件名称
   */
  listenerCount(eventName: string): number {
    return this.listeners.has(eventName) ? this.listeners.get(eventName)!.size : 0;
  }

  /**
   * 获取所有事件名称
   */
  eventNames(): string[] {
    return Array.from(this.listeners.keys());
  }

  /**
   * 清除所有事件监听器
   */
  removeAllListeners(): this {
    this.listeners.clear();
    return this;
  }
}
